import { Component, h, Prop, Host } from '@stencil/core';

@Component({
  tag: 'wdpr-progress-indicator',
  shadow: true,
})
export class WdprProgressIndicator {
  @Prop({ reflect: true }) progress: number = 0;
  @Prop({ reflect: true }) max: number = 100;
  @Prop({ reflect: true }) active: boolean = true;

  private get _percentage(): number {
    if (!Number.isFinite(this.max) || this.max <= 0) return 0;
    if (this.progress >= this.max) return 100;
    if (this.progress <= 0) return 0;
    
    return (this.progress / this.max) * 100;
  }

  private get _fillBgClass(): string {
    return this.active ? 'bg-surface-neutral-extra-dark' : this._trackBg;
  }

  private get _roundingClass(): string {
    return 'rounded-pill';
  }

  private get _trackBg(): string {
    return 'bg-surface-neutral-light';
  }

  render() {
    return (
      <Host>
        <div class="w-full" part="root">
          <div class={`relative h-075 overflow-hidden ${this._trackBg} ${this._roundingClass}`} part="track">
            <div class={`h-full ${this._fillBgClass} ${this._roundingClass}`} style={{ width: `${this._percentage}%` }} part="indicator" aria-hidden="true" />
            {this._percentage < 100 && (
              <div
              class="absolute top-[1px] right-[1px] w-dimension-050 h-dimension-050 shrink-0 bg-surface-neutral-extra-dark rounded-pill"
              part="stop-indicator"
              ></div>
            )}
          </div>
        </div>
      </Host>
    );
  }
}
